def twos_complement_binary_string(decimal_num, bit_length):
    if not isinstance(decimal_num, int):
        raise TypeError("Input 'decimal_num' must be an integer.")
    if not isinstance(bit_length, int) or bit_length <= 0:
        raise ValueError("Input 'bit_length' must be a positive integer.")

    max_positive = (1 << (bit_length - 1)) - 1
    min_negative = -(1 << (bit_length - 1))

    if not (min_negative <= decimal_num <= max_positive):
        raise ValueError(f"Number {decimal_num} is out of range for {bit_length}-bit two's complement representation. "
                         f"Range is [{min_negative}, {max_positive}].")

    if decimal_num >= 0:
        binary_representation = bin(decimal_num)[2:]
        return binary_representation.zfill(bit_length)
    else:
        twos_complement_value = (1 << bit_length) + decimal_num
        binary_representation = bin(twos_complement_value)[2:]
        return binary_representation.zfill(bit_length)
